mapper.select:
SELECT r.id,
       r.reship_no,
       r.order_id,
       r.ticket_id,
       r.shipment_id,
       r.reason_code,
       r.status,
       r.currency,
       r.items_cost,
       r.shipping_cost,
       r.note,
       r.created_at,
       r.updated_at
FROM aftersales_reship r


        AND r.reship_no = #{reshipNo}


        AND r.order_id = #{orderId}


        AND r.ticket_id = #{ticketId}


        AND r.status = #{status}


        AND r.reason_code = #{reasonCode}


        AND r.created_at  >=  #{createdFrom}


        AND r.created_at  <=  #{createdTo}


ORDER BY r.created_at DESC, r.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM aftersales_reship r


        AND r.reship_no = #{reshipNo}


        AND r.order_id = #{orderId}


        AND r.ticket_id = #{ticketId}


        AND r.status = #{status}


        AND r.reason_code = #{reasonCode}


        AND r.created_at  >=  #{createdFrom}


        AND r.created_at  <=  #{createdTo}

SELECT ri.id, ri.reship_id, ri.order_item_id, ri.sku_id, ri.quantity, ri.created_at, (oi.unit_price * ri.quantity) AS amount FROM aftersales_reship_item ri JOIN order_item oi ON oi.id = ri.order_item_id WHERE ri.reship_id IN
#{reshipId}
ORDER BY ri.reship_id, ri.id

SELECT rs.reship_id, rs.shipment_id, rs.created_at FROM aftersales_reship_shipment rs WHERE rs.reship_id IN
#{reshipId}
ORDER BY rs.reship_id, rs.created_at, rs.shipment_id
